SELECT year, COUNT(*) AS number_of_crashes
FROM crash_details
GROUP BY year;

SELECT COUNT(*) AS number_of_crashes, SUM(number_of_fatalities) AS total_fatalities
FROM crash_details
WHERE year = 2022;

SELECT AVG(crash_cost) AS avg_crash_cost
FROM crash_details
WHERE crash_type = 'head-on' AND crash_severity IN ('fatal', 'serious');
